import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import { 
  FaTrophy, FaStar, FaMedal, FaCode, FaFlag, FaCertificate 
} from 'react-icons/fa';
import './Accomplishments.css';

const Accomplishments = () => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.1
  });

  const achievements = [
    {
      icon: <FaTrophy />,
      title: 'Division 3 Ranking',
      description: 'Achieved on CodeChef'
    },
    {
      icon: <FaStar />,
      title: '1400+ Rating',
      description: 'CodeChef & LeetCode'
    },
    {
      icon: <FaMedal />,
      title: 'Top 15',
      description: 'Among 400+ students'
    },
    {
      icon: <FaCode />,
      title: '1000+ Problems',
      description: 'Solved across platforms'
    },
    {
      icon: <FaFlag />,
      title: '80+ Contests',
      description: 'Global competitions'
    }
  ];

  const certifications = [
    { name: 'Problem Solving in C', issuer: 'NPTEL' },
    { name: 'HTML, CSS, JavaScript', issuer: 'Coursera' },
    { name: 'Operating System Foundations', issuer: 'CISCO' },
    { name: 'DBMS (ELITE)', issuer: 'NPTEL' },
    { name: 'Python Essential 1 & 2', issuer: 'CISCO' }
  ];

  return (
    <section className="accomplishments" id="accomplishments">
      <div className="container">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 50 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <h2 className="section-title">Accomplishments</h2>

          <div className="achievements-grid">
            {achievements.map((achievement, index) => (
              <motion.div
                key={index}
                className="achievement-card"
                initial={{ opacity: 0, scale: 0.3, rotate: -180 }}
                animate={inView ? { opacity: 1, scale: 1, rotate: 0 } : {}}
                transition={{ 
                  delay: index * 0.1, 
                  duration: 0.8,
                  type: "spring",
                  stiffness: 120
                }}
                whileHover={{ 
                  y: -15, 
                  scale: 1.1,
                  rotate: 5,
                  transition: { duration: 0.3 }
                }}
              >
                <div className="achievement-icon">{achievement.icon}</div>
                <h3>{achievement.title}</h3>
                <p>{achievement.description}</p>
              </motion.div>
            ))}
          </div>

          <motion.div
            className="certifications-section"
            initial={{ opacity: 0, y: 30 }}
            animate={inView ? { opacity: 1, y: 0 } : {}}
            transition={{ delay: 0.6, duration: 0.6 }}
          >
            <h3 className="subsection-title">
              <FaCertificate /> Certifications
            </h3>
            <div className="certifications-grid">
              {certifications.map((cert, index) => (
                <motion.div
                  key={index}
                  className="cert-card"
                  initial={{ opacity: 0, x: -20 }}
                  animate={inView ? { opacity: 1, x: 0 } : {}}
                  transition={{ delay: 0.7 + index * 0.1, duration: 0.4 }}
                  whileHover={{ x: 10 }}
                >
                  <div className="cert-icon">
                    <FaCertificate />
                  </div>
                  <div className="cert-details">
                    <h4>{cert.name}</h4>
                    <p>{cert.issuer}</p>
                  </div>
                </motion.div>
              ))}
            </div>
          </motion.div>
        </motion.div>
      </div>
    </section>
  );
};

export default Accomplishments;
